namespace sv_e75d30b0b86442b6a4afa2d99c2aba48.Services;

public class WarehouseInfo
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

/// <summary>
/// Scoped service holding the currently selected warehouse for a single circuit.
/// Every interactive component in the circuit shares this instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

