@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@inject InventoryAlertState AlertState
@implements IAsyncDisposable

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Dashboard</h1>

<p class="text-muted">
    Viewing: <strong>@WarehouseState.SelectedWarehouseName</strong>
</p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_alertCardClass)">
            <div class="card-body">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4">@AlertState.LowStockCount</p>
                <p class="card-text text-muted">
                    Items below minimum level. Refreshes every 10 s.
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    private string _alertCardClass =>
        AlertState.LowStockCount > 10 ? "border-danger" :
        AlertState.LowStockCount > 5  ? "border-warning" :
        "border-success";

    protected override async Task OnInitializedAsync()
    {
        // Subscribe to warehouse changes so we re-poll immediately.
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Subscribe to alert state changes pushed by the polling loop.
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _alertHandler;

        await PollNowAsync();
        StartPolling();
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling against the new warehouse.
        await StopPollingAsync();
        await PollNowAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken token)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(token))
            {
                await PollNowAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse switch.
        }
    }

    private async Task PollNowAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(
            WarehouseState.SelectedWarehouseId);
        // Push through the shared state — all subscribers update.
        AlertState.UpdateCount(count);
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChange -= _warehouseHandler;
        AlertState.OnChange -= _alertHandler;
        await StopPollingAsync();
    }
}

